package com.facilcomanda.orderservice.entity; import com.facilcomanda.common.enums.OrderStatus; import jakarta.persistence.*; import java.math.BigDecimal; import java.time.LocalDateTime; import java.util.*; @Entity @Table(name="orders", indexes=@Index(name="idx_order_org", columnList="organization_id"), uniqueConstraints=@UniqueConstraint(columnNames={"organization_id","idempotency_key"})) public class Order { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(name="organization_id") private Long organizationId; private LocalDateTime orderDate; private String type; private String comments; @Column(name="idempotency_key") private String idempotencyKey; @Enumerated(EnumType.STRING) private OrderStatus status; @Column(name="restaurant_table_id") private Long restaurantTableId; @Column(name="user_id") private Long userId; @OneToMany(mappedBy="order", cascade=CascadeType.ALL, orphanRemoval=true) private List<OrderItem> orderItems=new ArrayList<>(); private BigDecimal total; @Version private Long version=0L; public void addOrderItem(OrderItem item){orderItems.add(item); item.setOrder(this);} public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getOrganizationId(){return organizationId;} public void setOrganizationId(Long organizationId){this.organizationId=organizationId;} public LocalDateTime getOrderDate(){return orderDate;} public void setOrderDate(LocalDateTime orderDate){this.orderDate=orderDate;} public String getType(){return type;} public void setType(String type){this.type=type;} public String getComments(){return comments;} public void setComments(String comments){this.comments=comments;} public String getIdempotencyKey(){return idempotencyKey;} public void setIdempotencyKey(String idempotencyKey){this.idempotencyKey=idempotencyKey;} public OrderStatus getStatus(){return status;} public void setStatus(OrderStatus status){this.status=status;} public Long getRestaurantTableId(){return restaurantTableId;} public void setRestaurantTableId(Long restaurantTableId){this.restaurantTableId=restaurantTableId;} public Long getUserId(){return userId;} public void setUserId(Long userId){this.userId=userId;} public List<OrderItem> getOrderItems(){return orderItems;} public void setOrderItems(List<OrderItem> orderItems){this.orderItems=orderItems;} public BigDecimal getTotal(){return total;} public void setTotal(BigDecimal total){this.total=total;} public Long getVersion(){return version;} public void setVersion(Long version){this.version=version;} }
